sql:
SELECT manufacturer_name, production_capacity
FROM vaccine_manufacturers
WHERE production_capacity = (
  SELECT MAX(production_capacity)
  FROM vaccine_manufacturers
);

external_knowledge:
- "blossomed" metaphorically refers to provinces where both the total number of vaccines administered and distributed are greater than zero;
- "seeds of administered and distributed vaccines" refers to the total_number_vaccines_administered and total_number_vaccines_distributed columns;
- "fallen barren" means that the sums of these columns are greater than zero, indicating active vaccination efforts.

- 'First, second, and booster doses' refer to different stages of vaccine administration;
- 'Rollout phases' are the different stages or periods during which vaccines are distributed and administered;
- 'Counting the seeds in different sections of a giant, multi-layered fruit' is a metaphor for aggregating and categorizing data.

- 'Provinces' are administrative divisions within a country;
- 'Vaccination percentage' is the ratio of the total number of vaccines administered to the total population, expressed as a percentage;
- ' Ranked from the most vaccinated to the least' means the provinces are ordered based on the vaccination percentage, from highest to lowest.

- "Vaccine administration percentage" is calculated as the total number of doses administered divided by the total number of doses distributed, multiplied by 100;
- "Top 5 provinces" refers to the provinces with the highest administration percentages;
- "Age groups" are categories used to classify individuals based on age ranges, such as "0-17", "18-49", etc.

- 'Top three vaccine administrations' refers to the three highest total numbers of vaccines administered in each province;
- 'Successful data exchanges' refers to data exchanges with a status of 'success';
- 'Monthly administration summary' is a specific reason for report requests.

sql:
SELECT COUNT(exchange_id) AS successful_exchanges
FROM data_exchange
WHERE status = 'success';

SELECT COUNT(DISTINCT manufacturer_id) AS unique_manufacturer_count
FROM (
    SELECT manufacturer_id FROM vaccine_distribution
    UNION
    SELECT manufacturer_id FROM vaccine_administration
);

SELECT SUM(total_number_vaccines_distributed) AS total_vaccines
FROM vaccine_distribution
WHERE manufacturer_id = 1;

SELECT 
    MIN(
        total_number_second_doses_administered - total_number_first_doses_administered
    ) AS minimum_dose_difference
FROM 
    vaccine_administration;

SELECT date_administered, COUNT(administration_id) AS daily_administration_count
FROM vaccine_administration
GROUP BY date_administered;

